) VALUES (
    '00000000-0000-0002-0001-000000000001',
    'customer-budgeting-002',
    'Budget Planning: Collaborative Exploration',
    'customer_facing',
    'Domain 5 (Budgeting)',
    'beginner',
    12,
    'Practice facilitative budget planning conversations using open questions and reflections to help customers explore their financial situation without directing or judging',
    'A customer wants to create a budget but feels overwhelmed and anxious about their spending. Your role is to use a facilitative approach - helping them explore their income, expenses, and priorities while respecting their autonomy. Domain 5 (Budgeting) requires impartial guidance that helps customers build financial capability without being directive. This scenario applies core skills to a specific MAPS context.',
    '{"name": "Taylor", "role": "customer seeking budgeting guidance", "background": "Has variable income and struggles to track expenses. Feels anxious about money and has tried budgeting before but didn''t stick with it. Wants to feel more in control but doesn''t want to be judged for spending choices.", "personality_traits": ["anxious", "overwhelmed", "hopeful", "self_critical"], "tone_spectrum": {"word_complexity": 0.4, "sentence_length": 0.4, "emotional_expressiveness": 0.5, "disclosure_level": 0.3, "response_latency": 0.4, "confidence_level": 0.3}, "starting_tone_position": 0.3, "triggers": ["judgment about spending", "being told what to do", "comparisons to others", "pressure to cut costs"], "comfort_topics": ["being understood", "having options", "control", "practical_support"]}'::jsonb,
    '{"start_node_id": "node_1", "nodes": {"node_1": {"id": "node_1", "persona_text": "I''ve tried to budget before, honestly. But I always fail at it. I''m not sure this time will be any different.", "persona_mood": "doubtful_defensive", "themes": ["Past Failure", "Self-Doubt"], "choice_points": [{"id": "cp_node_1_0", "option_text": "The key is to be more disciplined this time. We can set up a strict budget and you just need to stick to it.", "preview_hint": "This is directive advice", "rapport_impact": -1, "trust_impact": -1, "tone_shift": -0.1, "technique_tags": ["directive_advice"], "competency_links": [], "feedback": {"immediate": "This is directive advice, not facilitative coaching. In MAPS Domain 5, we help customers build their own capability, not impose solutions on them.", "learning_note": "Facilitative coaching supports autonomy - ''What would help you?'' rather than ''You must do this.''"}, "next_node_id": "node_2a", "exploration_depth": "surface"}, {"id": "cp_node_1_1", "option_text": "You''ve tried budgeting before but it hasn''t worked out, and you''re skeptical this time will be different.", "preview_hint": "This reflects their experience and doubt", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["simple_reflection"], "competency_links": ["A6", "A3"], "feedback": {"immediate": "Excellent reflection! You''ve validated their past experience without judgment. This helps them feel heard rather than defensive.", "learning_note": "Reflecting past budgeting difficulties helps customers feel understood - essential for Domain 5 work."}, "next_node_id": "node_2b", "exploration_depth": "surface"}, {"id": "cp_node_1_2", "option_text": "What made budgeting difficult for you in the past?", "preview_hint": "This open question explores barriers", "rapport_impact": 0, "trust_impact": 0, "tone_shift": 0.0, "technique_tags": ["open_question"], "competency_links": [], "feedback": {"immediate": "Good open question that invites exploration. After sharing vulnerability, this helps them process their experience while showing you''re interested in understanding.", "learning_note": "Open questions about past experience help identify barriers without being directive."}, "next_node_id": "node_2c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2a": {"id": "node_2a", "persona_text": "Exactly. Discipline isn''t my strong suit. Something always comes up and I spend more than I planned.", "persona_mood": "self_critical_discouraged", "themes": ["Self-Criticism", "Barriers"], "choice_points": [{"id": "cp_node_2a_0", "option_text": "Well, you need to build better discipline. Maybe set up automatic transfers so you save first and spend what''s left.", "preview_hint": "This is directive solution-giving", "rapport_impact": -1, "trust_impact": -1, "tone_shift": -0.1, "technique_tags": ["directive_advice"], "competency_links": [], "feedback": {"immediate": "This jumps to solutions rather than understanding their experience. In MAPS, we help customers discover what works for them, not prescribe solutions.", "learning_note": "Facilitative approach: ''What ideas do you have?'' rather than ''You should do X.''"}, "next_node_id": "node_3a", "exploration_depth": "surface"}, {"id": "cp_node_2a_1", "option_text": "You see discipline as a challenge, and something always seems to come up that affects your spending plan.", "preview_hint": "This reflects without judging", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["complex_reflection"], "competency_links": ["A6", "A3"], "feedback": {"immediate": "Good reflection! You''ve acknowledged their self-perception without agreeing or disagreeing. This opens space for exploring what''s really happening.", "learning_note": "Complex reflections capture both the challenge and the situation without judgment."}, "next_node_id": "node_3b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2b": {"id": "node_2b", "persona_text": "It''s just that unexpected expenses always seem to come up. Car repairs, medical bills, gifts... I feel like I can never get ahead.", "persona_mood": "frustrated_overwhelmed", "themes": ["Barriers", "Financial Stress"], "choice_points": [{"id": "cp_node_2b_0", "option_text": "That''s why you need an emergency fund built into your budget. That''s rule number one of budgeting.", "preview_hint": "This is prescriptive", "rapport_impact": 0, "trust_impact": 0, "tone_shift": 0.0, "technique_tags": ["education"], "competency_links": [], "feedback": {"immediate": "This is education rather than exploration. While true, it doesn''t help them feel understood. A better approach would be to explore their experience first.", "learning_note": "In MAPS Domain 5, we educate when appropriate but always with the customer''s perspective first."}, "next_node_id": "node_3c", "exploration_depth": "surface"}, {"id": "cp_node_2b_1", "option_text": "You''re frustrated because unexpected expenses keep coming up and you feel like you can never get ahead.", "preview_hint": "This reflects their emotional experience", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["simple_reflection"], "competency_links": ["A6", "A3"], "feedback": {"immediate": "Perfect reflection! You''ve captured both the pattern (unexpected expenses) and the emotional impact (never getting ahead). This validates their experience.", "learning_note": "Reflecting the emotional experience of financial stress builds trust in budgeting conversations."}, "next_node_id": "node_3d", "exploration_depth": "surface"}, {"id": "cp_node_2b_2", "option_text": "What kinds of unexpected expenses have you been dealing with?", "preview_hint": "This explores the specifics", "rapport_impact": 0, "trust_impact": 0, "tone_shift": 0.0, "technique_tags": ["open_question"], "competency_links": [], "feedback": {"immediate": "Good open question following the reflection! This helps them explore the specifics while feeling understood.", "learning_note": "Reflection then question is a powerful pattern for exploring financial situations."}, "next_node_id": "node_3e", "exploration_depth": "deep"}], "is_endpoint": false, "endpoint_type": null}, "node_2c": {"id": "node_2c", "persona_text": "I guess I just lose track of where my money goes. And then I''m short at the end of the month and have to use credit.", "persona_mood": "honest_self_aware", "themes": ["Awareness", "Pattern Recognition"], "choice_points": [{"id": "cp_node_2c_0", "option_text": "You recognize that you lose track of spending and then rely on credit to get by.", "preview_hint": "This reflects their pattern recognition", "rapport_impact": 1, "trust_impact": 1, "tone_shift": 0.15, "technique_tags": ["complex_reflection"], "competency_links": ["A6"], "feedback": {"immediate": "Excellent complex reflection! You''ve captured the pattern (lose track \u2192 short on cash \u2192 use credit) without judgment. This awareness is the first step to change.", "learning_note": "Complex reflections help people see patterns they might not recognize themselves."}, "next_node_id": "node_3f", "exploration_depth": "deep"}], "is_endpoint": false, "endpoint_type": null}, "node_3a": {"id": "node_3a", "persona_text": "I suppose you''re right. But I don''t know if I have the discipline to change.", "persona_mood": "resigned_hopeless", "themes": ["Resignation", "Low Confidence"], "choice_points": [], "is_endpoint": true, "endpoint_type": "low_confidence"}, "node_3b": {"id": "node_3b", "persona_text": "Thanks. It helps to talk about this without feeling judged.", "persona_mood": "relieved_open", "themes": ["Relief", "Openness"], "choice_points": [], "is_endpoint": true, "endpoint_type": "good_engagement"}, "node_3c": {"id": "node_3c", "persona_text": "That makes sense. But I still don''t know how to handle the unexpected stuff.", "persona_mood": "curious_but_stuck", "themes": ["Uncertainty", "Need for Solutions"], "choice_points": [], "is_endpoint": true, "endpoint_type": "needs_guidance"}, "node_3d": {"id": "node_3d", "persona_text": "Exactly. That''s exactly how it feels. Thanks for getting it.", "persona_mood": "validated_understood", "themes": ["Validation", "Trust"], "choice_points": [], "is_endpoint": true, "endpoint_type": "excellent_engagement"}, "node_3e": {"id": "node_3e", "persona_text": "Well, let me think... car repairs, medical bills, birthday gifts, sometimes helping out family... it just adds up.", "persona_mood": "exploring_insightful", "themes": ["Exploration", "Building Awareness"], "choice_points": [], "is_endpoint": true, "endpoint_type": "excellent_engagement"}, "node_3f": {"id": "node_3f", "persona_text": "Yeah. I hadn''t really thought about it as a pattern before. That helps.", "persona_mood": "insightful_motivated", "themes": ["Insight", "Motivation"], "choice_points": [], "is_endpoint": true, "endpoint_type": "excellent_engagement"}}}'::jsonb,
    ARRAY'[\"A6\", \"A3\", \"A5\", \"B6\"]',
    '{"dimensions": {"A6": {"description": "Rapport Building", "weight": 2.0, "positive_signals": ["reflection", "open_question", "non_judgmental"], "negative_signals": ["directive_advice", "prescriptive", "judgmental"]}, "A3": {"description": "Impartiality (Non-Directive)", "weight": 1.5, "positive_signals": ["exploratory", "respecting_autonomy", "facilitative"], "negative_signals": ["prescriptive", "directive", "imposing_solutions"]}, "A5": {"description": "Flexibility", "weight": 1.0, "positive_signals": ["adapting_approach", "responsive", "patient"], "negative_signals": ["rigid", "one_size_fits_all", "formulaic"]}, "B6": {"description": "Communication", "weight": 1.0, "positive_signals": ["collaborative_language", "exploratory_questions", "clear_expressions"], "negative_signals": ["jargon", "directive_statements", "lecture"]}}, "overall_scoring_logic": "weighted_average"}'::jsonb,
    '{"framework_name": "MaPS Money Guidance Competency Framework", "framework_version": "September 2022", "sections": ["A3", "A5", "A6", "B6"], "tier_relevance": "Tier 1-2 (Budgeting Guidance)", "domains": ["Domain 5: Budgeting"], "external_reference": "https://www.moneyandpensionsservice.org.uk/money-guidance-competency-framework"}'::jsonb,
    true
